              teachingCode: 'from Bio.Blast import NCBIXML\n\n# Parse BLAST results\nresult_handle = open("blast_results.xml")\nrecords = NCBIXML.parse(result_handle)\n\nfor record in records:\n    for alignment in record.alignments:\n        print(f"Hit: {alignment.hit_id}")\n        for hsp in alignment.hsps:\n            print(f"  E-value: {hsp.e}")\n            print(f"  Score: {hsp.score}")\n            print(f"  Identities: {hsp.identities}")\n            print(f"  Query: {hsp.query[:50]}...")\n            print(f"  Subject: {hsp.sbjct[:50]}...")',
