              teachingCode: '# Binary classification (e.g., cancer vs normal)\nmodel.compile(\n    optimizer="adam",\n    loss="binary_crossentropy",\n    metrics=["accuracy"]\n)\n\n# Multi-class classification (e.g., 5 cancer subtypes)\nmodel.compile(\n    optimizer="adam",\n    loss="categorical_crossentropy",\n    metrics=["accuracy"]\n)\n\n# Regression (e.g., predict binding affinity)\nmodel.compile(\n    optimizer="adam",\n    loss="mse",\n    metrics=["mae"]\n)',
