              teachingCode: 'import networkx as nx\n\nG = nx.Graph()\nG.add_edges_from([\n    ("TP53", "MDM2"), ("TP53", "BRCA1"),\n    ("TP53", "BAX"), ("MDM2", "E2F1")\n])\n\n# Degree of a node\nG.degree("TP53")   # 3 (connected to MDM2, BRCA1, BAX)\nG.degree("MDM2")   # 2 (connected to TP53, E2F1)\nG.degree("E2F1")   # 1\n\n# All degrees\ndict(G.degree())  # {"TP53": 3, "MDM2": 2, "BRCA1": 1, "BAX": 1, "E2F1": 1}\n\n# For directed graphs\n# D.in_degree(node)  — incoming edges\n# D.out_degree(node) — outgoing edges',
